// Extracteur de liens intelligent
const websiteUrl = $node["Webhook AI Enrich"].json.body.website;
const html = $input.first().json.data || "";

const cleanUrl = websiteUrl.replace('https://','').replace('http://','').split('/')[0];
const domain = cleanUrl;
const protocol = websiteUrl.startsWith('https') ? 'https' : 'http';
const baseUrl = `${protocol}://${domain}`;

// 1. Extraire tous les liens internes via Regex
const linkRegex = /href=["']([^#"'\s>]+)["']/gi;
const links = new Set();
let match;

// Ajouter la page initiale en premier
links.add(websiteUrl.startsWith('http') ? websiteUrl : `https://${websiteUrl}`);

while ((match = linkRegex.exec(html)) !== null) {
  let url = match[1];

  // Gérer les liens relatifs
  if (url.startsWith('/')) {
    url = `${baseUrl}${url}`;
  } else if (!url.startsWith('http')) {
    url = `${baseUrl}/${url}`;
  }

  // Garder seulement les liens du même domaine
  if (url.includes(domain) && !url.includes('tel:') && !url.includes('mailto:') && !url.endsWith('.jpg') && !url.endsWith('.png') && !url.endsWith('.pdf')) {
    links.add(url);
  }
}

// 2. Priorisation des pages stratégiques pour la prospection
const priorityTerms = ['about', 'propos', 'team', 'equipe', 'service', 'produit', 'product', 'contact', 'solution', 'client', 'realisation', 'projet'];

const sortedLinks = Array.from(links).map(url => {
  let priority = 100;
  priorityTerms.forEach((term, index) => {
    if (url.toLowerCase().includes(term)) priority = index;
  });
  // Homepage a la priorité absolue
  if (url === baseUrl || url === `${baseUrl}/`) priority = -1;
  return { url, priority };
});

sortedLinks.sort((a, b) => a.priority - b.priority);

// 3. Retourner les top 20 URLs
return sortedLinks.slice(0, 20).map(l => ({ url: l.url }));

// Nettoyage HTML et extraction du texte profond
const items = $input.all();
const cleanedPages = items.map((item, index) => {
  const html = item.json.data || "";

  // Nettoyage agressif des scripts et styles
  let text = html
    .replace(/<script[^>]*>.*?<\/script>/gis, '')
    .replace(/<style[^>]*>.*?<\/style>/gis, '')
    .replace(/<header[^>]*>.*?<\/header>/gis, '') // Optionnel: garder le header si on veut les menus
    .replace(/<footer[^>]*>.*?<\/footer>/gis, '') // Optionnel: garder le footer pour contacts
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

  // On garde un maximum de contenu informatif
  text = text.substring(0, 8000);

  return {
    page_number: index + 1,
    url: item.json.url || 'unknown',
    content: text
  };
});

return [{ json: { 
  pages: cleanedPages,
  count: cleanedPages.length 
} }];

// Consolidation finale optimisée
const aiResponse = $input.first().json.message?.content || '{}';
const originalBody = $node["Webhook AI Enrich"].json.body;

let data;
try {
  data = JSON.parse(aiResponse);
} catch (e) {
  data = { contact_info: {}, key_people: [], activities: {}, summary: "Analyse partielle" };
}

// Scoring dynamique basé sur la densité de données (Max 100)
let score = 30; // Base
if (originalBody.website) score += 10;

// Emails (Max 15)
const emailCount = data.contact_info?.emails?.length || 0;
if (emailCount > 0) score += 10;
if (emailCount > 1) score += 5;

// Téléphones (Max 10)
if (data.contact_info?.phones?.length > 0) score += 10;

// Personnes clés (Max 15)
const peopleCount = data.key_people?.length || 0;
score += Math.min(15, peopleCount * 5);

// Signaux d'affaires (Max 20)
const signalsCount = data.opportunities?.length || 0;
score += Math.min(20, signalsCount * 10);

return {
  json: {
    id: originalBody.id,
    score_global: Math.min(99, score),
    phone: data.contact_info?.phones?.[0] || null,
    email: data.contact_info?.emails?.[0] || null,
    address: data.contact_info?.addresses?.[0] || null,
    ai_intelligence: {
      contact_info: data.contact_info || {},
      key_people: data.key_people || [],
      activities: data.activities || {},
      recent_news: data.news || [],
      company_culture: data.culture || {},
      prospecting_opportunities: data.opportunities || [],
      sales_scripts: data.sales_scripts || [],
      executive_summary: data.summary || ""
    },
    enriched_at: new Date().toISOString()
  }
};
